<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Desktop</title>
<style>
  * { box-sizing: border-box; }
  html, body {
    margin: 0; padding: 0; width: 100%; height: 100%;
    font-family: "Segoe UI", Ubuntu, Arial, sans-serif;
    overflow: hidden;
    user-select: none;
  }

  #desktop {
    position: fixed;
    top: 0; left: 0; right: 0; bottom: 0;
    width: 100%; height: 100%;
    background: linear-gradient(160deg, #2c1e3a 0%, #4a2f5e 40%, #77216f 100%);
    overflow: hidden;
  }

  /* Top bar */
  #topbar {
    position: absolute;
    top: 0; left: 0; right: 0;
    height: 28px;
    background: rgba(20, 10, 25, 0.85);
    color: #eee;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 13px;
    letter-spacing: 0.5px;
    z-index: 5;
    backdrop-filter: blur(4px);
  }

  /* Desktop icons (decorative) */
  .desktop-icon {
    position: absolute;
    top: 50px;
    width: 80px;
    text-align: center;
    color: #fff;
    font-size: 12px;
    text-shadow: 0 1px 3px rgba(0,0,0,0.6);
  }
  .desktop-icon .glyph {
    font-size: 34px;
    display: block;
    margin-bottom: 4px;
  }
  #icon-files { left: 24px; }
  #icon-notepad { left: 24px; top: 140px; }

  /* Taskbar / dock */
  #taskbar {
    position: absolute;
    bottom: 0; left: 0; right: 0;
    height: 56px;
    background: rgba(15, 8, 20, 0.9);
    border-top: 1px solid rgba(255,255,255,0.08);
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 14px;
    z-index: 100;
    backdrop-filter: blur(6px);
  }

  .launcher {
    width: 42px;
    height: 42px;
    border-radius: 10px;
    background: #3c2b4d;
    border: 1px solid rgba(255,255,255,0.1);
    color: #fff;
    font-size: 20px;
    display: flex;
    align-items: center;
    justify-content: center;
    cursor: pointer;
    transition: background 0.15s, transform 0.1s;
  }
  .launcher:hover { background: #77216f; transform: translateY(-3px); }
  .launcher:active { transform: translateY(0); }

  /* Windows */
  .app-window {
    position: absolute;
    display: none;
    flex-direction: column;
    min-width: 360px;
    min-height: 240px;
    width: 520px;
    height: 380px;
    background: #2d2433;
    border-radius: 8px;
    border: 1px solid rgba(255,255,255,0.12);
    box-shadow: 0 20px 50px rgba(0,0,0,0.5);
    overflow: hidden;
    z-index: 10;
  }
  .app-window.active { z-index: 20; }

  .win-titlebar {
    height: 34px;
    background: #3c2b4d;
    display: flex;
    align-items: center;
    padding: 0 8px;
    cursor: move;
    flex-shrink: 0;
    color: #eee;
    font-size: 13px;
    border-bottom: 1px solid rgba(255,255,255,0.08);
  }
  .win-title {
    flex: 1;
    text-align: center;
    pointer-events: none;
  }
  .win-close {
    width: 20px; height: 20px;
    border-radius: 50%;
    background: #e0555a;
    border: none;
    color: #3a0000;
    font-size: 12px;
    line-height: 20px;
    text-align: center;
    cursor: pointer;
    padding: 0;
  }
  .win-close:hover { background: #ff6b70; }

  .win-body {
    flex: 1;
    display: flex;
    flex-direction: column;
    min-height: 0;
    background: #241d29;
    color: #eee;
  }

  /* Files app */
  #files-toolbar {
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 6px 10px;
    background: #2d2433;
    border-bottom: 1px solid rgba(255,255,255,0.08);
    flex-shrink: 0;
  }
  #files-up {
    background: #3c2b4d;
    border: 1px solid rgba(255,255,255,0.15);
    color: #eee;
    border-radius: 4px;
    padding: 4px 10px;
    cursor: pointer;
    font-size: 13px;
  }
  #files-up:hover { background: #4d3861; }
  #files-path {
    flex: 1;
    background: #1c151f;
    border: 1px solid rgba(255,255,255,0.1);
    border-radius: 4px;
    padding: 5px 8px;
    font-size: 13px;
    font-family: monospace;
    color: #c9a6d8;
    overflow: hidden;
    white-space: nowrap;
    text-overflow: ellipsis;
  }
  #files-listing {
    flex: 1;
    overflow-y: auto;
    padding: 10px;
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(84px, 1fr));
    gap: 8px;
    align-content: start;
  }
  .fs-item {
    display: flex;
    flex-direction: column;
    align-items: center;
    padding: 8px 4px;
    border-radius: 6px;
    cursor: default;
    font-size: 12px;
    text-align: center;
    word-break: break-word;
  }
  .fs-item:hover { background: rgba(255,255,255,0.08); }
  .fs-item.selected { background: rgba(119,33,111,0.5); }
  .fs-item .fs-glyph {
    font-size: 26px;
    margin-bottom: 4px;
  }

  /* Notepad app */
  #tabs {
    display: flex;
    align-items: center;
    background: #2d2433;
    border-bottom: 1px solid rgba(255,255,255,0.08);
    flex-shrink: 0;
    overflow-x: auto;
  }
  .tab {
    display: flex;
    align-items: center;
    gap: 6px;
    padding: 7px 10px;
    font-size: 12px;
    color: #ccc;
    cursor: pointer;
    border-right: 1px solid rgba(255,255,255,0.06);
    white-space: nowrap;
    max-width: 140px;
  }
  .tab.active {
    background: #241d29;
    color: #fff;
  }
  .tab-name {
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
  }
  .tab-close {
    background: transparent;
    border: none;
    color: #999;
    font-size: 13px;
    cursor: pointer;
    padding: 0 2px;
    line-height: 1;
  }
  .tab-close:hover { color: #ff6b70; }
  #new-tab {
    background: transparent;
    border: none;
    color: #ccc;
    font-size: 16px;
    cursor: pointer;
    padding: 4px 10px;
    flex-shrink: 0;
  }
  #new-tab:hover { color: #fff; }

  #editor {
    flex: 1;
    width: 100%;
    resize: none;
    border: none;
    outline: none;
    background: #1c151f;
    color: #eee;
    font-family: "Consolas", monospace;
    font-size: 14px;
    padding: 10px;
    line-height: 1.5;
  }
</style>
</head>
<body>

<div id="desktop">
  <div id="topbar">Activities &nbsp;•&nbsp; Ubuntu-ish Desktop</div>

  <div class="desktop-icon" id="icon-files">
    <span class="glyph">🗂️</span>Files
  </div>
  <div class="desktop-icon" id="icon-notepad">
    <span class="glyph">📝</span>Notepad
  </div>

  <!-- Files window -->
  <div class="app-window" id="files-window" style="left: 120px; top: 60px;">
    <div class="win-titlebar" data-target="files-window">
      <span style="width:20px"></span>
      <span class="win-title">Files</span>
      <button class="win-close" data-target="files-window">✕</button>
    </div>
    <div class="win-body">
      <div id="files-toolbar">
        <button id="files-up">⬆ Up</button>
        <div id="files-path">/</div>
      </div>
      <div id="files-listing"></div>
    </div>
  </div>

  <!-- Notepad window -->
  <div class="app-window" id="notepad-window" style="left: 260px; top: 120px;">
    <div class="win-titlebar" data-target="notepad-window">
      <span style="width:20px"></span>
      <span class="win-title">Notepad</span>
      <button class="win-close" data-target="notepad-window">✕</button>
    </div>
    <div class="win-body">
      <div id="tabs">
        <button id="new-tab" title="New tab">+</button>
      </div>
      <textarea id="editor" spellcheck="false"></textarea>
    </div>
  </div>

  <div id="taskbar">
    <div class="launcher" id="open-files" title="Files">🗂️</div>
    <div class="launcher" id="open-notepad" title="Notepad">📝</div>
  </div>
</div>

<script>
(function () {
  "use strict";

  /* ---------- Window management (open/close/drag/focus) ---------- */

  function bringToFront(win) {
    document.querySelectorAll('.app-window').forEach(w => w.classList.remove('active'));
    win.classList.add('active');
  }

  function openWindow(win) {
    win.style.display = 'flex';
    bringToFront(win);
  }

  function closeWindow(win) {
    win.style.display = 'none';
  }

  document.getElementById('open-files').addEventListener('click', function () {
    openWindow(document.getElementById('files-window'));
  });
  document.getElementById('open-notepad').addEventListener('click', function () {
    openWindow(document.getElementById('notepad-window'));
  });
  document.getElementById('icon-files').addEventListener('dblclick', function () {
    openWindow(document.getElementById('files-window'));
  });
  document.getElementById('icon-notepad').addEventListener('dblclick', function () {
    openWindow(document.getElementById('notepad-window'));
  });

  document.querySelectorAll('.win-close').forEach(function (btn) {
    btn.addEventListener('click', function (e) {
      e.stopPropagation();
      var target = document.getElementById(btn.getAttribute('data-target'));
      closeWindow(target);
    });
  });

  document.querySelectorAll('.app-window').forEach(function (win) {
    win.addEventListener('mousedown', function () { bringToFront(win); });
  });

  // Dragging via title bar
  document.querySelectorAll('.win-titlebar').forEach(function (bar) {
    bar.addEventListener('mousedown', function (e) {
      if (e.target.classList.contains('win-close')) return;
      var win = document.getElementById(bar.getAttribute('data-target'));
      bringToFront(win);
      var desktopRect = document.getElementById('desktop').getBoundingClientRect();
      var startX = e.clientX;
      var startY = e.clientY;
      var winRect = win.getBoundingClientRect();
      var startLeft = winRect.left - desktopRect.left;
      var startTop = winRect.top - desktopRect.top;

      function onMove(ev) {
        var dx = ev.clientX - startX;
        var dy = ev.clientY - startY;
        var newLeft = startLeft + dx;
        var newTop = startTop + dy;
        newTop = Math.max(0, newTop);
        win.style.left = newLeft + 'px';
        win.style.top = newTop + 'px';
      }
      function onUp() {
        document.removeEventListener('mousemove', onMove);
        document.removeEventListener('mouseup', onUp);
      }
      document.addEventListener('mousemove', onMove);
      document.addEventListener('mouseup', onUp);
    });
  });

  /* ---------- Files app (static fake filesystem) ---------- */

  var FS = {
    name: '/', type: 'folder', children: [
      { name: 'bin', type: 'folder', children: [
        { name: 'bash', type: 'file' },
        { name: 'ls', type: 'file' },
        { name: 'cat', type: 'file' }
      ]},
      { name: 'etc', type: 'folder', children: [
        { name: 'hostname', type: 'file' },
        { name: 'passwd', type: 'file' },
        { name: 'fstab', type: 'file' }
      ]},
      { name: 'home', type: 'folder', children: [
        { name: 'user', type: 'folder', children: [
          { name: 'Documents', type: 'folder', children: [
            { name: 'resume.txt', type: 'file' },
            { name: 'notes.md', type: 'file' }
          ]},
          { name: 'Downloads', type: 'folder', children: [
            { name: 'installer.deb', type: 'file' }
          ]},
          { name: 'Pictures', type: 'folder', children: [
            { name: 'wallpaper.png', type: 'file' },
            { name: 'screenshot.png', type: 'file' }
          ]},
          { name: '.bashrc', type: 'file' }
        ]}
      ]},
      { name: 'usr', type: 'folder', children: [
        { name: 'local', type: 'folder', children: [] },
        { name: 'share', type: 'folder', children: [] }
      ]},
      { name: 'var', type: 'folder', children: [
        { name: 'log', type: 'folder', children: [
          { name: 'syslog', type: 'file' }
        ]},
        { name: 'www', type: 'folder', children: [] }
      ]}
    ]
  };

  var currentPath = [];

  function getNodeAtPath(path) {
    var node = FS;
    for (var i = 0; i < path.length; i++) {
      var found = null;
      for (var j = 0; j < node.children.length; j++) {
        if (node.children[j].name === path[i]) { found = node.children[j]; break; }
      }
      if (!found) return null;
      node = found;
    }
    return node;
  }

  function renderFiles() {
    var node = getNodeAtPath(currentPath);
    var pathStr = '/' + currentPath.join('/');
    document.getElementById('files-path').textContent = pathStr === '/' ? '/' : pathStr;

    var listing = document.getElementById('files-listing');
    listing.innerHTML = '';

    var children = (node && node.children) ? node.children.slice() : [];
    children.sort(function (a, b) {
      if (a.type !== b.type) return a.type === 'folder' ? -1 : 1;
      return a.name.localeCompare(b.name);
    });

    children.forEach(function (child) {
      var el = document.createElement('div');
      el.className = 'fs-item';
      el.setAttribute('data-type', child.type);

      var glyph = document.createElement('span');
      glyph.className = 'fs-glyph';
      glyph.textContent = child.type === 'folder' ? '📁' : '📄';

      var label = document.createElement('span');
      label.className = 'fs-name';
      label.textContent = child.name;

      el.appendChild(glyph);
      el.appendChild(label);

      el.addEventListener('click', function () {
        document.querySelectorAll('.fs-item.selected').forEach(function (s) { s.classList.remove('selected'); });
        el.classList.add('selected');
      });

      if (child.type === 'folder') {
        el.addEventListener('dblclick', function () {
          currentPath.push(child.name);
          renderFiles();
        });
      }

      listing.appendChild(el);
    });
  }

  document.getElementById('files-up').addEventListener('click', function () {
    if (currentPath.length > 0) {
      currentPath.pop();
      renderFiles();
    }
  });

  renderFiles();

  /* ---------- Notepad app (tabbed, persistent via localStorage) ---------- */

  var STORAGE_KEY = 'desktop_notepad_state_v1';
  var notepadState = { tabs: [], activeId: null };
  var nextTabId = 1;

  function loadNotepadState() {
    try {
      var raw = localStorage.getItem(STORAGE_KEY);
      if (raw) {
        var parsed = JSON.parse(raw);
        if (parsed && Array.isArray(parsed.tabs) && parsed.tabs.length > 0) {
          notepadState = parsed;
          var maxId = 0;
          notepadState.tabs.forEach(function (t) {
            var idNum = parseInt(t.id.replace('tab-', ''), 10);
            if (!isNaN(idNum) && idNum > maxId) maxId = idNum;
          });
          nextTabId = maxId + 1;
          return;
        }
      }
    } catch (e) { /* ignore corrupt storage */ }

    // Default initial tab
    var id = 'tab-' + (nextTabId++);
    notepadState.tabs = [{ id: id, title: 'untitled.txt', content: '' }];
    notepadState.activeId = id;
  }

  function saveNotepadState() {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(notepadState));
  }

  function getActiveTab() {
    for (var i = 0; i < notepadState.tabs.length; i++) {
      if (notepadState.tabs[i].id === notepadState.activeId) return notepadState.tabs[i];
    }
    return notepadState.tabs[0] || null;
  }

  function deriveTitle(content, fallback) {
    var firstLine = (content || '').split('\n')[0].trim();
    if (firstLine.length > 0) {
      return firstLine.length > 16 ? firstLine.slice(0, 16) + '…' : firstLine;
    }
    return fallback;
  }

  function renderTabs() {
    var tabsEl = document.getElementById('tabs');
    // Remove existing .tab elements, keep #new-tab button
    tabsEl.querySelectorAll('.tab').forEach(function (t) { t.remove(); });

    var newTabBtn = document.getElementById('new-tab');

    notepadState.tabs.forEach(function (tab) {
      var tabEl = document.createElement('div');
      tabEl.className = 'tab' + (tab.id === notepadState.activeId ? ' active' : '');
      tabEl.setAttribute('data-id', tab.id);

      var nameEl = document.createElement('span');
      nameEl.className = 'tab-name';
      nameEl.textContent = tab.title || 'untitled.txt';

      var closeEl = document.createElement('button');
      closeEl.className = 'tab-close';
      closeEl.textContent = '✕';
      closeEl.title = 'Close tab';

      tabEl.appendChild(nameEl);
      tabEl.appendChild(closeEl);

      tabEl.addEventListener('click', function (e) {
        if (e.target === closeEl) return;
        notepadState.activeId = tab.id;
        saveNotepadState();
        renderTabs();
        renderEditor();
      });

      closeEl.addEventListener('click', function (e) {
        e.stopPropagation();
        closeTab(tab.id);
      });

      tabsEl.insertBefore(tabEl, newTabBtn);
    });
  }

  function renderEditor() {
    var active = getActiveTab();
    var editor = document.getElementById('editor');
    editor.value = active ? active.content : '';
    editor.disabled = !active;
  }

  function closeTab(id) {
    var idx = notepadState.tabs.findIndex(function (t) { return t.id === id; });
    if (idx === -1) return;
    notepadState.tabs.splice(idx, 1);

    if (notepadState.tabs.length === 0) {
      var newId = 'tab-' + (nextTabId++);
      notepadState.tabs.push({ id: newId, title: 'untitled.txt', content: '' });
      notepadState.activeId = newId;
    } else if (notepadState.activeId === id) {
      var newIdx = Math.max(0, idx - 1);
      notepadState.activeId = notepadState.tabs[newIdx].id;
    }

    saveNotepadState();
    renderTabs();
    renderEditor();
  }

  document.getElementById('new-tab').addEventListener('click', function () {
    var id = 'tab-' + (nextTabId++);
    notepadState.tabs.push({ id: id, title: 'untitled.txt', content: '' });
    notepadState.activeId = id;
    saveNotepadState();
    renderTabs();
    renderEditor();
  });

  document.getElementById('editor').addEventListener('input', function (e) {
    var active = getActiveTab();
    if (!active) return;
    active.content = e.target.value;
    active.title = deriveTitle(active.content, active.title || 'untitled.txt');
    saveNotepadState();
    renderTabs();
  });

  loadNotepadState();
  renderTabs();
  renderEditor();

})();
</script>

</body>
</html>
